File: lichen/subsys/lichen/routing/gradient.c
Lines: 82-104

In find_lru():

    static struct lichen_gradient_entry *find_lru(struct lichen_gradient_table *table)
    {
        struct lichen_gradient_entry *lru = NULL;
        uint32_t oldest_time = 0xFFFFFFFF;  // <-- initialized but never read

        for (size_t i = 0; i < CONFIG_LICHEN_ROUTING_GRADIENT_MAX_ENTRIES; i++) {
            ...
            if (lru == NULL || (int32_t)(e->last_used_ms - lru->last_used_ms) < 0) {
                lru = e;
                oldest_time = e->last_used_ms;  // <-- assigned but never used
            }
        }
        return lru;
    }

The variable oldest_time is assigned but never read. The comparison correctly uses lru->last_used_ms directly. This is dead code that should be removed for clarity.
